namespace optiling {

static inline uint32_t AlignDown(uint32_t x, uint32_t a)
{
    return (x / a) * a;
}

static inline uint32_t CeilDiv(uint32_t a, uint32_t b)
{
    return (a + b - 1u) / b;
}

// UB model for this fused kernel: we'll fill output in tiles, only one queue
// outQueue: 2 * tile
// bytes = 8 * tile (2 buffers) -> conservative UB budget to keep headroom
static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 2048;
static constexpr uint32_t HARD_CAP_ELEMS = 32768;

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    Conv3dSoftmaxMaxPoolMaxPoolCustomTilingData tiling;

    // Read input tensor shapes
    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_shape = context->GetInputShape(1);
    if (x_shape->GetDimNum() != 5 || w_shape->GetDimNum() != 5) {
        return ge::GRAPH_FAILED;
    }

    const uint32_t n   = static_cast<uint32_t>(x_shape->GetDim(0));
    const uint32_t cin = static_cast<uint32_t>(x_shape->GetDim(1));
    const uint32_t inD = static_cast<uint32_t>(x_shape->GetDim(2));
    const uint32_t inH = static_cast<uint32_t>(x_shape->GetDim(3));
    const uint32_t inW = static_cast<uint32_t>(x_shape->GetDim(4));

    const uint32_t cout = static_cast<uint32_t>(w_shape->GetDim(0));
    const uint32_t kD   = static_cast<uint32_t>(w_shape->GetDim(2));
    const uint32_t kH   = static_cast<uint32_t>(w_shape->GetDim(3));
    const uint32_t kW   = static_cast<uint32_t>(w_shape->GetDim(4));

    // Attributes (defaults match the provided model)
    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int32_t *stride_d = attrs->GetAttrPointer<int32_t>(0);
    const int32_t *stride_h = attrs->GetAttrPointer<int32_t>(1);
    const int32_t *stride_w = attrs->GetAttrPointer<int32_t>(2);
    const int32_t *pad_d    = attrs->GetAttrPointer<int32_t>(3);
    const int32_t *pad_h    = attrs->GetAttrPointer<int32_t>(4);
    const int32_t *pad_w    = attrs->GetAttrPointer<int32_t>(5);
    const int32_t *dil_d    = attrs->GetAttrPointer<int32_t>(6);
    const int32_t *dil_h    = attrs->GetAttrPointer<int32_t>(7);
    const int32_t *dil_w    = attrs->GetAttrPointer<int32_t>(8);
    const int32_t *groups   = attrs->GetAttrPointer<int32_t>(9);

    const int32_t sd = (stride_d != nullptr) ? *stride_d : 1;
    const int32_t sh = (stride_h != nullptr) ? *stride_h : 1;
    const int32_t sw = (stride_w != nullptr) ? *stride_w : 1;
    const int32_t pd = (pad_d    != nullptr) ? *pad_d    : 0;
    const int32_t ph = (pad_h    != nullptr) ? *pad_h    : 0;
    const int32_t pw = (pad_w    != nullptr) ? *pad_w    : 0;
    const int32_t dd = (dil_d    != nullptr) ? *dil_d    : 1;
    const int32_t dh = (dil_h    != nullptr) ? *dil_h    : 1;
    const int32_t dw = (dil_w    != nullptr) ? *dil_w    : 1;
    (void)groups; // not used in this sample

    // Conv3d output dims (N, Cout, D1, H1, W1)
    const int32_t kd_eff = (kD - 1) * dd + 1;
    const int32_t kh_eff = (kH - 1) * dh + 1;
    const int32_t kw_eff = (kW - 1) * dw + 1;
    const uint32_t outD1 = static_cast<uint32_t>((static_cast<int32_t>(inD) + 2 * pd - kd_eff) / sd + 1);
    const uint32_t outH1 = static_cast<uint32_t>((static_cast<int32_t>(inH) + 2 * ph - kh_eff) / sh + 1);
    const uint32_t outW1 = static_cast<uint32_t>((static_cast<int32_t>(inW) + 2 * pw - kw_eff) / sw + 1);

    // Two successive MaxPool3d with kernel=2, stride=2 equals kernel=4, stride=4
    const uint32_t poolK = 4, poolS = 4, poolP = 0, poolDil = 1;
    const uint32_t outD = static_cast<uint32_t>(((int32_t)outD1 + 2 * poolP - poolDil * (poolK - 1) - 1) / poolS + 1);
    const uint32_t outH = static_cast<uint32_t>(((int32_t)outH1 + 2 * poolP - poolDil * (poolK - 1) - 1) / poolS + 1);
    const uint32_t outW = static_cast<uint32_t>(((int32_t)outW1 + 2 * poolP - poolDil * (poolK - 1) - 1) / poolS + 1);

    const uint32_t totalLen = n * cout * outD * outH * outW;

    // Tile length from UB budget (two out buffers), 4 bytes per float
    uint32_t maxTile = (UB_BUDGET_BYTES / 2) / 4;
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;
    if (maxTile > HARD_CAP_ELEMS) maxTile = AlignDown(HARD_CAP_ELEMS, ALIGN_ELEMS);

    uint32_t tileLen = maxTile;
    if (totalLen < tileLen) {
        const uint32_t aligned = AlignDown(totalLen, ALIGN_ELEMS);
        tileLen = (aligned > 0) ? aligned : totalLen;
    }
    if (tileLen == 0) tileLen = 1;

    uint32_t numTiles = CeilDiv(totalLen, tileLen);
    uint32_t blockDim = numTiles;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;

    context->SetBlockDim(blockDim);

    tiling.set_n(n);
    tiling.set_cin(cin);
    tiling.set_cout(cout);
    tiling.set_inD(inD);
    tiling.set_inH(inH);
    tiling.set_inW(inW);
    tiling.set_kD(kD);
    tiling.set_kH(kH);
    tiling.set_kW(kW);
    tiling.set_outD1(outD1);
    tiling.set_outH1(outH1);
    tiling.set_outW1(outW1);
    tiling.set_outD(outD);
    tiling.set_outH(outH);
    tiling.set_outW(outW);
    tiling.set_totalLength(totalLen);
    tiling.set_tileLength(tileLen);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

